def _encode_check_value_value(csil_v):
    if isinstance(csil_v, str):
        return [0, csil_v]
    if isinstance(csil_v, int):
        return [1, csil_v]
    if isinstance(csil_v, float):
        return [2, csil_v]
    raise ValueError("csil cbor: value does not match any check_value variant")


def _decode_check_value_value(csil_tree):
    if not isinstance(csil_tree, (list, tuple)) or len(csil_tree) != 2:
        raise CsilDecodeError("csil cbor: check_value union expects a 2-element array")
    csil_idx = csil_tree[0]
    csil_val = csil_tree[1]
    if csil_idx == 0:
        return _csil_expect_text(csil_val)
    if csil_idx == 1:
        return _csil_expect_int(csil_val)
    if csil_idx == 2:
        return _csil_expect_float(csil_val)
    raise CsilDecodeError("csil cbor: unknown check_value variant")
